function makeFlaky() {
  let n = 0;
  return new Proxy({ length: 1 }, {
    get(t, k) {
      if (k === '0') { n++; return { price: n, qty: 1 }; }
      return t[k];
    },
  });
}

const cases = [
  ['empty array', () => []],
  ['one item', () => [{ price: 2, qty: 3 }]],
  ['two items', () => [{ price: 2, qty: 3 }, { price: 5, qty: 1 }]],
  ['falsy elements mixed', () => [null, { price: 2, qty: 3 }, undefined, 0, false, '']],
